// ==========================================
// 📘 STATIC PROPERTIES & METHODS
// ==========================================

class User {
    constructor(username){
        this.username = username
    }

    logMe(){
        console.log(`Username: ${this.username}`);
    }

    // Static Method
    static createId(){
        return `123`
    }
}


const hitesh = new User("hitesh")

// console.log(hitesh.createId()) // ❌ Error
// Static methods cannot be called on instances


// Correct way - Access using class name
console.log(User.createId());
// Output: 123

// ==========================================
// 📘 Child Class
// ==========================================

class Teacher extends User {
    constructor(username, email){
        super(username)
        this.email = email
    }
}

const iphone = new Teacher("iphone", "i@phone.com")

// console.log(iphone.createId()) // ❌ Error
// Static methods are NOT inherited by instances

// Only accessible via class name
console.log(User.createId());
